import type Graphic from "../../Graphic.js";
import type EsriError from "../../core/Error.js";
import type SharedTemplateMetadata from "../../editing/sharedTemplates/SharedTemplateMetadata.js";
import type FormTemplate from "../../form/FormTemplate.js";
import type Mesh from "../../geometry/Mesh.js";
import type Point from "../../geometry/Point.js";
import type Polygon from "../../geometry/Polygon.js";
import type Polyline from "../../geometry/Polyline.js";
import type SubtypeGroupLayer from "../../layers/SubtypeGroupLayer.js";
import type CatalogFootprintLayer from "../../layers/catalog/CatalogFootprintLayer.js";
import type KnowledgeGraphSublayer from "../../layers/knowledgeGraph/KnowledgeGraphSublayer.js";
import type FeatureTemplate from "../../layers/support/FeatureTemplate.js";
import type SubtypeSublayer from "../../layers/support/SubtypeSublayer.js";
import type Attachments from "../Attachments.js";
import type FeatureForm from "../FeatureForm.js";
import type FeatureTemplates from "../FeatureTemplates.js";
import type SketchViewModel from "../Sketch/SketchViewModel.js";
import type { EditableLayerUnion } from "../../layers/types.js";
